 818 static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
 819   // Use of assumptions is context-sensitive. If we don't have a context, we
 820   // cannot use them!
 821   if (!Q.AC || !Q.CxtI)
 822     return false;
